mapper.update:
UPDATE ai_document_vector
SET is_active = false, updated_at = NOW()
WHERE document_id = #{documentId}

UPDATE ai_document_vector
SET is_active = false, updated_at = NOW()
WHERE session_id = #{sessionId}

UPDATE ai_document_vector
SET is_active = false, updated_at = NOW()
WHERE knowledge_document_id = #{knowledgeDocumentId}

mapper.select:
SELECT v.* FROM ai_document_vector v INNER JOIN ai_document d ON d.knowledge_document_id = v.knowledge_document_id WHERE v.is_active = true AND d.is_active = true AND d.status = #{status,javaType=com.example.agent.rag.enums.RagDocumentStatus,typeHandler=org.apache.ibatis.type.EnumTypeHandler}
AND (d.session_id = #{sessionId} OR d.session_id IS NULL)
AND d.session_id IS NULL
ORDER BY v.updated_at DESC, v.document_id DESC LIMIT #{limit}
